INSERT INTO public.courses (id, created_by, title, description, track, difficulty, duration_hours, is_published)
VALUES
  ('00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000000', 'Vascular Ultrasound Fundamentals', 'Learn the basics of duplex ultrasound for vascular assessment including B-mode imaging, Doppler waveforms, and common pathologies.', 'vascular-ultrasound', 'beginner', 4, true),
  ('00000000-0000-0000-0000-000000000002', '00000000-0000-0000-0000-000000000000', 'PAD Assessment & Management', 'Comprehensive course on peripheral arterial disease: clinical evaluation, ABI measurement, imaging interpretation, and treatment algorithms.', 'pad-limb', 'intermediate', 6, true),
  ('00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000000', 'Aortic Pathology Essentials', 'From aneurysm surveillance to acute aortic syndrome management. Covers imaging, risk stratification, and intervention criteria.', 'aorta', 'intermediate', 5, true),
  ('00000000-0000-0000-0000-000000000004', '00000000-0000-0000-0000-000000000000', 'Venous Thromboembolism Workshop', 'Deep vein thrombosis and pulmonary embolism: diagnosis, anticoagulation, catheter-directed therapy, and long-term follow-up.', 'thrombosis', 'advanced', 3, true),
  ('00000000-0000-0000-0000-000000000005', '00000000-0000-0000-0000-000000000000', 'Chronic Venous Disease Management', 'Understand venous insufficiency from CEAP classification to modern interventions: thermal ablation, sclerotherapy, and compression.', 'venous', 'beginner', 3, true)
INSERT INTO public.modules (id, course_id, title, module_type, sort_order, content)
VALUES
  ('00000000-0000-0000-0001-000000000001', '00000000-0000-0000-0000-000000000001', 'Introduction to Duplex Ultrasound', 'lesson', 1, 'Duplex ultrasound combines B-mode imaging with Doppler flow analysis. It is the first-line non-invasive tool for vascular assessment. This module covers transducer selection, patient positioning, and basic scanning techniques.'),
  ('00000000-0000-0000-0001-000000000002', '00000000-0000-0000-0000-000000000001', 'Arterial Doppler Waveforms', 'lesson', 2, 'Learn to recognize triphasic, biphasic, and monophasic waveforms. Understand spectral broadening, peak systolic velocity, and end-diastolic velocity ratios for stenosis grading.'),
  ('00000000-0000-0000-0001-000000000003', '00000000-0000-0000-0000-000000000002', 'ABI Measurement Technique', 'practical', 1, 'Step-by-step guide to ankle-brachial index measurement including equipment setup, cuff placement, Doppler probe positioning, and result interpretation.'),
  ('00000000-0000-0000-0001-000000000004', '00000000-0000-0000-0000-000000000002', 'PAD Imaging Interpretation', 'lesson', 2, 'CTA and MRA interpretation for peripheral arterial disease: identifying stenoses, occlusions, collateral pathways, and planning interventions.'),
  ('00000000-0000-0000-0001-000000000005', '00000000-0000-0000-0000-000000000003', 'Aortic Aneurysm Surveillance', 'lesson', 1, 'Guidelines for abdominal and thoracic aortic aneurysm monitoring: measurement techniques, growth rates, and intervention thresholds.'),
  ('00000000-0000-0000-0001-000000000006', '00000000-0000-0000-0000-000000000004', 'DVT Diagnosis Protocol', 'lesson', 1, 'Wells score, D-dimer testing, and compression ultrasound technique for deep vein thrombosis diagnosis.'),
  ('00000000-0000-0000-0001-000000000007', '00000000-0000-0000-0000-000000000005', 'CEAP Classification', 'lesson', 1, 'Understanding the Clinical-Etiology-Anatomy-Pathophysiology classification system for chronic venous disease.')
INSERT INTO public.simulations (id, created_by, title, description, category, difficulty, is_published, scenario, time_limit_seconds)
VALUES
  ('00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0000-000000000000', 'Acute Limb Ischemia — Emergency Triage', 'A 67-year-old patient presents to the ED with sudden onset of cold, painful right leg. Work through the diagnostic and management algorithm.', 'pad', 'intermediate', true, '{"steps":[{"id":"step1","title":"Initial Assessment","description":"Patient presents with 6F rule: Pain, Pallor, Pulselessness, Paresthesia, Paralysis, Poikilothermia. Right leg is cold and pale below the knee. No palpable dorsalis pedis or posterior tibial pulses.","options":[{"label":"Order urgent CTA of lower extremities","next":"step2","correct":true},{"label":"Start IV heparin and observe for 24h","next":"step3","correct":false},{"label":"Consult orthopedics for compartment syndrome","next":"step3","correct":false}]},{"id":"step2","title":"CTA Results","description":"CTA shows acute occlusion of the right popliteal artery with no reconstitution distally. Good collateral flow from the profunda femoris.","options":[{"label":"Initiate systemic heparin and prepare for catheter-directed thrombolysis","next":"step4","correct":true},{"label":"Schedule elective bypass surgery next week","next":"step3","correct":false},{"label":"Start aspirin and discharge with follow-up","next":"step3","correct":false}]},{"id":"step3","title":"Suboptimal Choice","description":"This approach delays critical treatment. In acute limb ischemia, time is tissue. Reconsider your approach.","options":[{"label":"Go back and reconsider","next":"step1","correct":true}]},{"id":"step4","title":"Treatment Decision","description":"Heparin started. The vascular surgery team is assembled. Patient has Rutherford IIa ischemia (marginally threatened).","options":[{"label":"Proceed with catheter-directed thrombolysis","next":"step5","correct":true},{"label":"Proceed with surgical thromboembolectomy","next":"step5","correct":true}]},{"id":"step5","title":"Outcome","description":"Excellent result. Flow restored in the popliteal and tibial arteries. Patient will require long-term anticoagulation workup and follow-up surveillance.","options":[]}]}', 900),
  ('00000000-0000-0000-0002-000000000002', '00000000-0000-0000-0000-000000000000', 'Ruptured AAA — Rapid Decision Making', 'A 74-year-old male collapses with severe back pain and hypotension. Manage this time-critical aortic emergency.', 'aortic', 'advanced', true, '{"steps":[{"id":"step1","title":"Emergency Presentation","description":"Patient arrives unconscious, BP 70/40, HR 130. Known 6.5cm infrarenal AAA from prior imaging. Abdomen is distended and tender.","options":[{"label":"Activate massive transfusion protocol and call vascular surgery","next":"step2","correct":true},{"label":"Order CT scan to confirm diagnosis","next":"step3","correct":false},{"label":"Start fluids and wait for stabilization","next":"step3","correct":false}]},{"id":"step2","title":"OR Decision","description":"Vascular team ready. Patient partially stabilized with 2 units PRBCs. BP now 85/55.","options":[{"label":"Emergent open repair (tube graft)","next":"step4","correct":true},{"label":"Emergent EVAR if anatomy suitable","next":"step4","correct":true}]},{"id":"step3","title":"Critical Delay","description":"In suspected ruptured AAA with hemodynamic instability, delays increase mortality dramatically. Go directly to treatment.","options":[{"label":"Reconsider approach","next":"step1","correct":true}]},{"id":"step4","title":"Successful Repair","description":"Aneurysm repaired. Patient in ICU. Key learning: permissive hypotension, avoid CT delays in obvious cases, and have a team protocol ready.","options":[]}]}', 600),
  ('00000000-0000-0000-0002-000000000003', '00000000-0000-0000-0000-000000000000', 'Carotid Stenosis Evaluation', 'Evaluate a 72-year-old patient with a recent TIA and determine the appropriate management strategy for carotid stenosis.', 'carotid', 'beginner', true, '{"steps":[{"id":"step1","title":"Clinical Presentation","description":"72-year-old patient had a transient right-hand weakness and speech difficulty lasting 20 minutes yesterday. No residual deficit. BP 150/85.","options":[{"label":"Order carotid duplex ultrasound","next":"step2","correct":true},{"label":"Start aspirin and schedule follow-up in 3 months","next":"step3","correct":false},{"label":"Admit for brain MRI only","next":"step3","correct":false}]},{"id":"step2","title":"Ultrasound Results","description":"Left ICA shows PSV 320 cm/s with EDV 120 cm/s, consistent with 70-89% stenosis. Right ICA normal.","options":[{"label":"Confirm with CTA and refer for CEA/CAS evaluation","next":"step4","correct":true},{"label":"Medical management only with dual antiplatelet","next":"step3","correct":false}]},{"id":"step3","title":"Incomplete Workup","description":"Symptomatic carotid stenosis >50% benefits from revascularization within 2 weeks. Delays increase stroke risk.","options":[{"label":"Reconsider","next":"step1","correct":true}]},{"id":"step4","title":"Treatment Planning","description":"CTA confirms 75% left ICA stenosis. Patient is a good surgical candidate. CEA scheduled within 14 days with perioperative aspirin and statin.","options":[]}]}', 600)
